import type { EditorView } from '@codemirror/view';
import { type RefObject, useEffect, useReducer, useRef } from 'react';

import { HistoryIcon } from '@dynatrace/strato-icons';

import { useRecentFilters } from './useRecentFilters.js';
import { TimeIndicator } from '../../../../core/components/time-indicator/TimeIndicator.js';
import { Text } from '../../../../typography/text/Text.js';
import { recentFiltersEffect } from '../../editor-state-configs/editor-config.js';
import type { FilterFieldSuggestion } from '../../suggestions/Suggestion.types.js';

/**
 * Syncs the namespaced store of the filter field to the suggestions.
 */
export function useRecentFilterSuggestions(
  editorViewRef: RefObject<EditorView>,
  filterNamespace: string | null = null,
): void {
  const recentFilters = useRecentFilters(filterNamespace);

  const editorViewRefChange = useRef(editorViewRef.current);
  const [state, forceUpdate] = useReducer((x) => x + 1, 0);

  if (editorViewRefChange.current !== editorViewRef.current) {
    editorViewRefChange.current = editorViewRef.current;
    forceUpdate();
  }

  useEffect(() => {
    if (editorViewRef.current && recentFilters && recentFilters.length > 0) {
      const recentFiltersSuggestions = recentFilters.map<FilterFieldSuggestion>(
        (storedFilter) => ({
          value: storedFilter.filter,
          insertionStrategy: 'replace-all',
          icon: <HistoryIcon />,
          displayValue: storedFilter.filter,

          /* TODO
           * Discussed with @peter.affenzeller.
           * The details are by default rendered below the displayValue.
           * Only a container query moves it over to the right. Check with UX if this is
           */
          details: storedFilter.timeUsed && (
            <Text textStyle="small">
              <TimeIndicator time={storedFilter.timeUsed.getTime()} />
            </Text>
          ),
        }),
      );

      editorViewRef.current.dispatch({
        effects: [recentFiltersEffect.of(recentFiltersSuggestions)],
      });
    }
    // recentFilters needs to be stringified.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [state, editorViewRef.current, JSON.stringify(recentFilters)]);
}
